import{_ as t,c as a,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Invalid Grant: Auto-Disable Recovery | Antigravity-Manager","description":"Learn how to handle invalid_grant errors. Understand account auto-disable and recovery methods in Antigravity-Manager.","frontmatter":{"title":"Invalid Grant: Auto-Disable Recovery | Antigravity-Manager","sidebarTitle":"Invalid Grant","subtitle":"invalid_grant and Account Auto-Disable: Why It Happens and How to Recover","description":"Learn how to handle invalid_grant errors. Understand account auto-disable and recovery methods in Antigravity-Manager.","tags":["FAQ","Troubleshooting","OAuth","Account Management","invalid_grant"],"prerequisite":["start-add-account","start-first-run-data","advanced-scheduling"],"order":999},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md","filePath":"lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"}'),n={name:"lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"};function i(s,e,l,d,c,h){return o(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="invalid-grant-and-account-auto-disable-why-it-happens-and-how-to-recover" tabindex="-1">invalid_grant and Account Auto-Disable: Why It Happens and How to Recover <a class="header-anchor" href="#invalid-grant-and-account-auto-disable-why-it-happens-and-how-to-recover" aria-label="Permalink to &quot;invalid_grant and Account Auto-Disable: Why It Happens and How to Recover&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>When you see <code>invalid_grant</code>, know which type of refresh_token issue it corresponds to</li><li>Understand &quot;why the account suddenly became unavailable&quot;: what triggers auto-disable and how the system handles it</li><li>Recover accounts with the shortest path and confirm recovery takes effect for running Proxy</li></ul><h2 id="symptoms-you-may-encounter" tabindex="-1">Symptoms You May Encounter <a class="header-anchor" href="#symptoms-you-may-encounter" aria-label="Permalink to &quot;Symptoms You May Encounter&quot;">​</a></h2><ul><li>Sudden failures when calling local Proxy, with <code>invalid_grant</code> appearing in error messages</li><li>Account is still in the Accounts list, but Proxy always skips it (or you feel it&#39;s &quot;never being used again&quot;)</li><li>When you have only a small number of accounts, encountering one <code>invalid_grant</code> noticeably reduces overall availability</li></ul><h2 id="what-is-invalid-grant" tabindex="-1">What Is invalid_grant? <a class="header-anchor" href="#what-is-invalid-grant" aria-label="Permalink to &quot;What Is invalid_grant?&quot;">​</a></h2><p><strong>invalid_grant</strong> is a type of error returned by Google OAuth when refreshing <code>access_token</code>. For Antigravity-Manager, it means an account&#39;s <code>refresh_token</code> has likely been revoked or expired, and continuing to retry will only repeatedly fail. Therefore, the system marks that account as unavailable and removes it from the proxy pool.</p><h2 id="core-concept-the-system-doesn-t-temporarily-skip-it-permanently-disables" tabindex="-1">Core Concept: The System Doesn&#39;t &quot;Temporarily Skip&quot;, It &quot;Permanently Disables&quot; <a class="header-anchor" href="#core-concept-the-system-doesn-t-temporarily-skip-it-permanently-disables" aria-label="Permalink to &quot;Core Concept: The System Doesn&#39;t &quot;Temporarily Skip&quot;, It &quot;Permanently Disables&quot;&quot;">​</a></h2><p>When Proxy detects that the error string during token refresh contains <code>invalid_grant</code>, it does two things:</p><ol><li><strong>Mark the account as disabled</strong> (persisted to account JSON)</li><li><strong>Remove the account from in-memory token pool</strong> (avoiding repeatedly selecting the same broken account)</li></ol><p>This is why you see &quot;the account is still there, but Proxy doesn&#39;t use it anymore.&quot;</p><div class="info custom-block"><p class="custom-block-title">disabled vs proxy_disabled</p><ul><li><code>disabled=true</code>: Account is &quot;completely disabled&quot; (typical reason is <code>invalid_grant</code>). It&#39;s directly skipped when loading the account pool.</li><li><code>proxy_disabled=true</code>: Account is only &quot;unavailable to Proxy&quot; (manual disable/batch operations/quota protection related logic), with different semantics.</li></ul><p>These two states are judged separately when loading the account pool: first check <code>disabled</code>, then perform quota protection and <code>proxy_disabled</code> checks.</p></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-confirm-it-s-invalid-grant-triggered-by-refresh-token-refresh" tabindex="-1">Step 1: Confirm It&#39;s invalid_grant Triggered by refresh_token Refresh <a class="header-anchor" href="#step-1-confirm-it-s-invalid-grant-triggered-by-refresh-token-refresh" aria-label="Permalink to &quot;Step 1: Confirm It&#39;s invalid_grant Triggered by refresh_token Refresh&quot;">​</a></h3><p><strong>Why</strong>: <code>invalid_grant</code> can appear in multiple call chains, but this project&#39;s &quot;auto-disable&quot; only triggers when <strong>refresh access_token fails</strong>.</p><p>In Proxy logs, you&#39;ll see error logs like this (keywords are <code>Token refresh failed</code> + <code>invalid_grant</code>):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Token refresh failed (&lt;email&gt;): &lt;...invalid_grant...&gt;, trying next account</span></span>
<span class="line"><span>Disabling account due to invalid_grant (&lt;email&gt;): refresh_token likely revoked/expired</span></span></code></pre></div><p><strong>You should see</strong>: After the same account encounters <code>invalid_grant</code>, it&#39;s quickly no longer selected (because it was removed from token pool).</p><h3 id="step-2-check-the-disabled-field-in-account-file-optional-but-most-accurate" tabindex="-1">Step 2: Check the disabled Field in Account File (Optional, But Most Accurate) <a class="header-anchor" href="#step-2-check-the-disabled-field-in-account-file-optional-but-most-accurate" aria-label="Permalink to &quot;Step 2: Check the disabled Field in Account File (Optional, But Most Accurate)&quot;">​</a></h3><p><strong>Why</strong>: Auto-disable is &quot;persisted&quot;. After confirming file contents, you can rule out misjudgment as &quot;just temporary rotation.&quot;</p><p>Account files are located in the <code>accounts/</code> directory of the application data directory (for data directory location, see <strong><a href="/docs/opencodedocs/lbjlaq/Antigravity-Manager/start/first-run-data/">First Run Essentials: Data Directory, Logs, Tray, and Auto-Startup</a></strong>). When an account is disabled, these three fields appear in the file:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1700000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;invalid_grant: ...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>You should see</strong>: <code>disabled</code> is <code>true</code>, and <code>disabled_reason</code> contains the <code>invalid_grant:</code> prefix.</p><h3 id="step-3-recover-account-recommended-approach-re-add-the-same-account" tabindex="-1">Step 3: Recover Account (Recommended Approach: Re-Add the Same Account) <a class="header-anchor" href="#step-3-recover-account-recommended-approach-re-add-the-same-account" aria-label="Permalink to &quot;Step 3: Recover Account (Recommended Approach: Re-Add the Same Account)&quot;">​</a></h3><p><strong>Why</strong>: This project&#39;s &quot;recovery&quot; isn&#39;t manually toggling a switch in Proxy, but triggering auto-reenabling through &quot;explicitly updating token.&quot;</p><p>Go to the <strong>Accounts</strong> page and re-add the account with your new credentials (choose either of two methods):</p><ol><li>Go through OAuth authorization flow again (see <strong><a href="/docs/opencodedocs/lbjlaq/Antigravity-Manager/start/add-account/">Add Account: OAuth/Refresh Token Dual Channel and Best Practices</a></strong>)</li><li>Add again with a new <code>refresh_token</code> (the system will use the email returned by Google as the basis for upsert)</li></ol><p>When the system detects that the <code>refresh_token</code> or <code>access_token</code> from this upsert is different from the old value, and that account was previously in <code>disabled=true</code> state, it will automatically clear:</p><ul><li><code>disabled</code></li><li><code>disabled_reason</code></li><li><code>disabled_at</code></li></ul><p><strong>You should see</strong>: The account is no longer in disabled state, and (if Proxy is running) the account pool will be automatically reloaded, making recovery take effect immediately.</p><h3 id="step-4-verify-recovery-has-taken-effect-for-proxy" tabindex="-1">Step 4: Verify Recovery Has Taken Effect for Proxy <a class="header-anchor" href="#step-4-verify-recovery-has-taken-effect-for-proxy" aria-label="Permalink to &quot;Step 4: Verify Recovery Has Taken Effect for Proxy&quot;">​</a></h3><p><strong>Why</strong>: If you only have one account, or if other accounts are also unavailable, you should immediately see &quot;availability is back&quot; after recovery.</p><p>Verification method:</p><ol><li>Initiate a request that triggers token refresh (e.g., wait for token to approach expiration before requesting)</li><li>Observe that logs no longer show &quot;skip disabled account&quot; prompts</li></ol><p><strong>You should see</strong>: Requests pass normally, and logs no longer show the <code>invalid_grant</code> disable process for that account.</p><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="❌-treating-disabled-as-temporary-rotation" tabindex="-1">❌ Treating disabled as &quot;Temporary Rotation&quot; <a class="header-anchor" href="#❌-treating-disabled-as-temporary-rotation" aria-label="Permalink to &quot;❌ Treating disabled as &quot;Temporary Rotation&quot;&quot;">​</a></h3><p>If you only look at &quot;the account is still there&quot; in the UI, it&#39;s easy to misjudge it as &quot;the system is just not using it temporarily.&quot; But <code>disabled=true</code> is written to disk and continues to take effect after restart.</p><h3 id="❌-only-adding-access-token-not-updating-refresh-token" tabindex="-1">❌ Only Adding access_token, Not Updating refresh_token <a class="header-anchor" href="#❌-only-adding-access-token-not-updating-refresh-token" aria-label="Permalink to &quot;❌ Only Adding access_token, Not Updating refresh_token&quot;">​</a></h3><p>The trigger point for <code>invalid_grant</code> is the <code>refresh_token</code> used when refreshing <code>access_token</code>. If you only temporarily obtained an <code>access_token</code> that still works, but <code>refresh_token</code> remains invalid, it will still trigger disable again later.</p><h2 id="checkpoints-✅" tabindex="-1">Checkpoints ✅ <a class="header-anchor" href="#checkpoints-✅" aria-label="Permalink to &quot;Checkpoints ✅&quot;">​</a></h2><ul><li>[ ] You can confirm in logs that <code>invalid_grant</code> comes from refresh_token refresh failure</li><li>[ ] You know the semantic difference between <code>disabled</code> and <code>proxy_disabled</code></li><li>[ ] You can recover accounts by re-adding accounts (OAuth or refresh_token)</li><li>[ ] You can verify that recovery has taken effect for the running Proxy</li></ul><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><ul><li>When <code>invalid_grant</code> is triggered, Proxy <strong>persists the account as disabled</strong> to disk and removes it from the token pool to avoid repeated failures</li><li>The key to recovery is &quot;explicitly updating the token&quot; (re-OAuth or adding again with a new refresh_token); the system will automatically clear <code>disabled_*</code> fields</li><li>The account JSON in the data directory is the authoritative source of state (disable/reason/time are all in there)</li></ul><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="/docs/opencodedocs/lbjlaq/Antigravity-Manager/faq/auth-401/">401/Authentication Failure: auth_mode, Header Compatibility, and Client Configuration Checklist</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>Which layer of &quot;Mode/Key/Header&quot; 401 typically doesn&#39;t match</li><li>What authentication headers different clients should carry</li><li>How to self-check and fix via the shortest path</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Lines</th></tr></thead><tbody><tr><td>Design explanation: invalid_grant issues and changed behavior</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy-invalid-grant.md#L1-L52" target="_blank" rel="noreferrer"><code>docs/proxy-invalid-grant.md</code></a></td><td>1-52</td></tr><tr><td>Skip <code>disabled=true</code> when loading account pool</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L70-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>70-158</td></tr><tr><td>Recognize <code>invalid_grant</code> when token refresh fails and disable account</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L840-L890" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>840-890</td></tr><tr><td>Persist <code>disabled/disabled_at/disabled_reason</code> to disk and remove from memory</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L942-L969" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>942-969</td></tr><tr><td><code>disabled_reason</code> truncation (avoid account file bloat)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1464-L1471" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1464-1471</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table></details>`,49)])])}const g=t(n,[["render",i]]);export{p as __pageData,g as default};
